1280→router.post('/update-username', requireAuth, async (req, res) => {
1281→    const userId = req.userId;
1282→    const { username } = req.body;
1283→
1284→    if (!username || typeof username !== 'string') {
1285→        return res.status(400).json({ error: 'username is required' });
1286→    }
1287→
1288→    const trimmed = username.trim();
1289→    if (trimmed.length < 3 || trimmed.length > 50) {
1290→        return res.status(400).json({ error: 'username must be 3-50 characters' });
1291→    }
1292→
1293→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
1294→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
1295→    }
1296→
1297→    const normalized = trimmed.toLowerCase();
1298→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
1299→    if (RESERVED_WORDS.includes(normalized)) {
1300→        return res.status(400).json({ error: 'this username is reserved' });
1301→    }
1302→
1303→    // Check uniqueness
1304→    const { data: existing } = await supabase
1305→        .from('users')
1306→        .select('id')
1307→        .ilike('username', normalized)
1308→        .neq('id', userId)
1309→        .limit(1);
1310→
1311→    if (existing && existing.length > 0) {
1312→        return res.status(409).json({ error: 'username is already taken' });
1313→    }
1314→
1315→    const { error: updateError } = await supabase
1316→        .from('users')
1317→        .update({ username: trimmed.toLowerCase() })
1318→        .eq('id', userId);
1319→
1320→    if (updateError) {
1321→        console.error('update-username error:', updateError.message);
1322→        return res.status(500).json({ error: 'failed to update username' });
1323→    }
1324→
1325→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
1326→});
