 1→import supabase from "./supabase.js"
 2→
 3→export const getUserByUsernameService = async(username) => {
 4→    if(!username || typeof username !== 'string'){
 5→        throw {status: 400, message: 'username is required'};
 6→    }
 7→
 8→    const normalizedUsername = username.trim().toLowerCase();
 9→
10→    const { data: users, error: userError } = await supabase
11→        .from('users')
12→        .select('*')
13→        .ilike('username', normalizedUsername)
14→        .limit(1);
15→
16→    if(userError){
17→        console.error('supabase error fetching user by username:', userError.message);
18→        throw {status: 500, message: 'supabase error fetching user by username'};
19→    }
20→
21→    if(!users || users.length === 0){
22→        throw {status: 404, message: 'user not found'};
23→    }
24→
25→    const user = users[0];
26→
27→    const followerCountPromise = supabase
28→        .from('follows')
29→        .select('*', {count: 'exact', head: true})
30→        .eq('following_id', user.id);
31→
32→    const followingCountPromise = supabase
33→        .from('follows')
34→        .select('*', {count: 'exact', head: true})
35→        .eq('follower_id', user.id);
36→
37→    const [followerCountResult, followingCountResult] = await Promise.all([
38→        followerCountPromise, followingCountPromise
39→    ]);
40→
41→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
42→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
43→
44→    if(errorFollowerCount || errorFollowingCount){
45→        console.error('supabase error fetching follow counts:', errorFollowerCount || errorFollowingCount);
46→    }
47→
48→    return {
49→        userData: [user],
50→        followerCount: followerCount || 0,
51→        followingCount: followingCount || 0
52→    };
53→}
