1509→    }
1510→
1511→    const parsedLimit = parseInt(limit);
1512→    if(isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > SEARCH_LIMIT_MAX){
1513→        throw {status: 400, error: `limit should be an integer between 1 and ${SEARCH_LIMIT_MAX}`};
1514→    }
1515→
1516→    const escapedQuery = normalizedQuery.replace(/[%_]/g, (match) => `\\${match}`);
1517→    const selectColumns = 'id, name, username, image_url, badge';
1518→
1519→    const [nameResult, usernameResult] = await Promise.all([
1520→        supabase
1521→            .from('users')
1522→            .select(selectColumns)
1523→            .ilike('name', `%${escapedQuery}%`)
1524→            .limit(parsedLimit + 1),
1525→        supabase
1526→            .from('users')
1527→            .select(selectColumns)
1528→            .ilike('username', `%${escapedQuery}%`)
1529→            .limit(parsedLimit + 1)
1530→    ]);
1531→
1532→    if(nameResult.error || usernameResult.error){
1533→        console.error('user search error:', nameResult.error?.message || usernameResult.error?.message);
1534→        throw {status: 500, error: 'supabase error while searching users'};
1535→    }
1536→
1537→    const userMap = new Map();
1538→    (nameResult.data || []).forEach((user) => {
1539→        userMap.set(user.id, user);
1540→    });
1541→    (usernameResult.data || []).forEach((user) => {
1542→        if(!userMap.has(user.id)){
1543→            userMap.set(user.id, user);
1544→        }
1545→    });
1546→
1547→    const users = [...userMap.values()];
1548→    const hasMore = users.length > parsedLimit;
1549→
1550→    return {
1551→        data: hasMore ? users.slice(0, parsedLimit) : users,
1552→        hasMore: hasMore
1553→    };
1554→}
