 53→/**
 54→ * Record a publish event for streak tracking.
 55→ * Called after a new journal/opinion/chapter is published.
 56→ * Returns { streakData, milestone } where milestone is 7|14|30|50|100|null.
 57→ */
 58→export const recordPublishForStreak = async (userId) => {
 59→    if (!userId) return { streakData: null, milestone: null };
 60→
 61→    const today = getUTCDateString();
 62→
 63→    // Fetch existing streak row
 64→    const { data: existing, error: fetchErr } = await supabase
 65→        .from('writing_streaks')
 66→        .select('*')
 67→        .eq('user_id', userId)
 68→        .maybeSingle();
 69→
 70→    if (fetchErr) {
 71→        console.error('error fetching streak for record:', fetchErr.message);
 72→        return { streakData: null, milestone: null };
 73→    }
 74→
 75→    // No existing row → first publish ever
 76→    if (!existing) {
 77→        const newRow = {
 78→            user_id: userId,
 79→            current_streak: 1,
 80→            longest_streak: 1,
 81→            last_publish_date: today,
 82→            freeze_available: false,
 83→            updated_at: new Date().toISOString(),
 84→        };
 85→
 86→        const { error: insertErr } = await supabase
 87→            .from('writing_streaks')
 88→            .insert(newRow);
 89→
 90→        if (insertErr) {
 91→            console.error('error inserting streak:', insertErr.message);
 92→            return { streakData: null, milestone: null };
 93→        }
 94→
 95→        return { streakData: newRow, milestone: null };
 96→    }
 97→
 98→    // Already published today → no-op
 99→    if (existing.last_publish_date === today) {
100→        return { streakData: existing, milestone: null };
101→    }
102→
103→    const gap = daysBetween(existing.last_publish_date, today);
104→
105→    let newStreak = existing.current_streak;
106→    let freezeAvailable = existing.freeze_available;
107→    let freezeUsedDate = existing.freeze_used_date;
108→    let freezeUsed = false;
109→
110→    if (gap === 1) {
111→        // Consecutive day
112→        newStreak += 1;
113→    } else if (gap === 2 && freezeAvailable) {
114→        // Missed exactly 1 day, auto-use freeze
115→        newStreak += 1;
116→        freezeAvailable = false;
117→        freezeUsedDate = today;
118→        freezeUsed = true;
119→    } else {
120→        // Streak broken
121→        newStreak = 1;
122→    }
123→
124→    const newLongest = Math.max(existing.longest_streak, newStreak);
125→
126→    // Grant a new freeze every 7 days of streak (if not already available)
127→    if (!freezeAvailable && newStreak > 0 && newStreak % 7 === 0) {
128→        const lastGranted = existing.freeze_last_granted;
129→        if (!lastGranted || lastGranted !== today) {
130→            freezeAvailable = true;
131→        }
132→    }
133→
134→    const updatePayload = {
135→        current_streak: newStreak,
136→        longest_streak: newLongest,
137→        last_publish_date: today,
138→        freeze_available: freezeAvailable,
139→        freeze_used_date: freezeUsedDate,
140→        freeze_last_granted: freezeAvailable ? today : existing.freeze_last_granted,
141→        updated_at: new Date().toISOString(),
142→    };
143→
144→    const { error: updateErr } = await supabase
145→        .from('writing_streaks')
146→        .update(updatePayload)
147→        .eq('user_id', userId);
148→
149→    if (updateErr) {
150→        console.error('error updating streak:', updateErr.message);
151→        return { streakData: null, milestone: null };
152→    }
153→
154→    // Check for milestone
155→    const milestone = MILESTONES.includes(newStreak) ? newStreak : null;
156→
157→    return {
158→        streakData: { ...existing, ...updatePayload },
159→        milestone,
160→        freezeUsed,
161→    };
162→};
